"""Built-in mini-corpus of real NLP / ML papers (offline fallback + tests).

~40 well-known papers (title + short abstract + arXiv categories) spanning NLP
subfields, so semantic search, faceting and topic clustering produce meaningful
results with no downloads. On Colab a large HF corpus is used instead.
"""

from __future__ import annotations

from typing import Dict, List

PAPERS: List[Dict] = [
    {"title": "Attention Is All You Need",
     "abstract": "We propose the Transformer, a network architecture based solely on attention mechanisms, dispensing with recurrence and convolutions entirely. Experiments on machine translation show the model is superior in quality while being more parallelizable and requiring less time to train.",
     "categories": "cs.CL cs.LG"},
    {"title": "BERT: Pre-training of Deep Bidirectional Transformers for Language Understanding",
     "abstract": "We introduce BERT, which is designed to pretrain deep bidirectional representations from unlabeled text by jointly conditioning on both left and right context. The pre-trained model can be fine-tuned with one additional output layer to obtain state-of-the-art results on a wide range of tasks.",
     "categories": "cs.CL"},
    {"title": "GPT-3: Language Models are Few-Shot Learners",
     "abstract": "We train an autoregressive language model with 175 billion parameters and test its performance in the few-shot setting. The model achieves strong performance on many NLP tasks without gradient updates, using only text interaction with the model.",
     "categories": "cs.CL"},
    {"title": "RoBERTa: A Robustly Optimized BERT Pretraining Approach",
     "abstract": "We present a replication study of BERT pretraining that carefully measures the impact of many key hyperparameters and training data size. We find that BERT was significantly undertrained and propose an improved recipe that matches or exceeds later models.",
     "categories": "cs.CL"},
    {"title": "DistilBERT, a distilled version of BERT: smaller, faster, cheaper and lighter",
     "abstract": "We propose a method to pre-train a smaller general-purpose language representation model using knowledge distillation. The resulting model retains most of the language understanding capabilities while being 40% smaller and 60% faster.",
     "categories": "cs.CL"},
    {"title": "ELECTRA: Pre-training Text Encoders as Discriminators Rather Than Generators",
     "abstract": "We propose a more sample-efficient pre-training task called replaced token detection, in which the model learns to distinguish real input tokens from plausible but synthetically generated replacements. This formulation is more compute-efficient than masked language modeling.",
     "categories": "cs.CL"},
    {"title": "Sentence-BERT: Sentence Embeddings using Siamese BERT-Networks",
     "abstract": "We present a modification of the pretrained BERT network that uses siamese and triplet network structures to derive semantically meaningful sentence embeddings that can be compared using cosine similarity, enabling efficient semantic search and clustering.",
     "categories": "cs.CL"},
    {"title": "Dense Passage Retrieval for Open-Domain Question Answering",
     "abstract": "We show that retrieval can be implemented using dense representations alone, with embeddings learned from a small number of questions and passages by a simple dual-encoder framework. Dense retrieval outperforms a strong BM25 baseline on open-domain question answering.",
     "categories": "cs.CL cs.IR"},
    {"title": "Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks",
     "abstract": "We explore a general-purpose fine-tuning recipe for retrieval-augmented generation, models that combine pre-trained parametric and non-parametric memory for language generation. RAG models set the state of the art on several knowledge-intensive tasks.",
     "categories": "cs.CL"},
    {"title": "SPECTER: Document-level Representation Learning using Citation-informed Transformers",
     "abstract": "We propose a method to generate document-level embeddings of scientific papers based on pretraining a transformer on a powerful signal of document relatedness: the citation graph. SPECTER embeddings perform well on document-level tasks without task-specific fine-tuning.",
     "categories": "cs.CL cs.IR cs.DL"},
    {"title": "Sequence to Sequence Learning with Neural Networks",
     "abstract": "We present a general end-to-end approach to sequence learning that uses multilayered LSTM to map the input sequence to a vector of a fixed dimensionality, and then another deep LSTM to decode the target sequence from the vector. The method achieves strong machine translation results.",
     "categories": "cs.CL cs.LG"},
    {"title": "Neural Machine Translation by Jointly Learning to Align and Translate",
     "abstract": "We conjecture that the use of a fixed-length vector is a bottleneck and propose to extend this by allowing a model to automatically search for parts of a source sentence that are relevant to predicting a target word. This attention mechanism significantly improves translation.",
     "categories": "cs.CL cs.LG"},
    {"title": "GloVe: Global Vectors for Word Representation",
     "abstract": "We propose a global log-bilinear regression model that combines the advantages of global matrix factorization and local context window methods to learn word vector representations. The model efficiently leverages statistical information and produces meaningful substructure.",
     "categories": "cs.CL"},
    {"title": "Efficient Estimation of Word Representations in Vector Space (word2vec)",
     "abstract": "We propose two novel model architectures for computing continuous vector representations of words from very large data sets. The quality of these representations is measured in a word similarity task, showing large improvements in accuracy at much lower computational cost.",
     "categories": "cs.CL"},
    {"title": "Deep Contextualized Word Representations (ELMo)",
     "abstract": "We introduce a new type of deep contextualized word representation that models both complex characteristics of word use and how these uses vary across linguistic contexts. The representations are learned from a deep bidirectional language model.",
     "categories": "cs.CL"},
    {"title": "T5: Exploring the Limits of Transfer Learning with a Unified Text-to-Text Transformer",
     "abstract": "We introduce a unified framework that converts every language problem into a text-to-text format, and systematically study transfer learning for NLP. Combined with scale, this approach achieves state-of-the-art results on many benchmarks.",
     "categories": "cs.CL cs.LG"},
    {"title": "BART: Denoising Sequence-to-Sequence Pre-training for Natural Language Generation",
     "abstract": "We present a denoising autoencoder for pretraining sequence-to-sequence models, trained by corrupting text with an arbitrary noising function and learning to reconstruct the original. BART is effective for text generation and comprehension tasks.",
     "categories": "cs.CL"},
    {"title": "XLNet: Generalized Autoregressive Pretraining for Language Understanding",
     "abstract": "We propose a generalized autoregressive pretraining method that enables learning bidirectional contexts by maximizing the expected likelihood over all permutations of the factorization order, overcoming the limitations of BERT.",
     "categories": "cs.CL"},
    {"title": "Longformer: The Long-Document Transformer",
     "abstract": "We introduce an attention mechanism that scales linearly with sequence length, making it easy to process documents of thousands of tokens. The model combines local windowed attention with task-motivated global attention.",
     "categories": "cs.CL"},
    {"title": "A Neural Probabilistic Language Model",
     "abstract": "We propose to fight the curse of dimensionality by learning a distributed representation for words which allows each training sentence to inform the model about an exponential number of semantically neighboring sentences.",
     "categories": "cs.CL cs.LG"},
    {"title": "Named Entity Recognition with Bidirectional LSTM-CNNs",
     "abstract": "We present a neural network architecture that automatically detects word- and character-level features using a hybrid bidirectional LSTM and CNN, removing the need for most feature engineering in named entity recognition.",
     "categories": "cs.CL"},
    {"title": "End-to-end Sequence Labeling via Bi-directional LSTM-CNNs-CRF",
     "abstract": "We introduce a neural network architecture that benefits from both word- and character-level representations automatically, using a combination of bidirectional LSTM, CNN and CRF, for sequence labeling tasks such as POS tagging and NER.",
     "categories": "cs.CL"},
    {"title": "Get To The Point: Summarization with Pointer-Generator Networks",
     "abstract": "We propose a hybrid pointer-generator architecture that can copy words from the source text via pointing, aiding accurate reproduction of information while retaining the ability to produce novel words, for abstractive summarization.",
     "categories": "cs.CL"},
    {"title": "SQuAD: 100,000+ Questions for Machine Comprehension of Text",
     "abstract": "We present a reading comprehension dataset consisting of questions posed by crowdworkers on Wikipedia articles, where the answer to each question is a segment of text from the corresponding passage. We analyze the dataset to understand the reasoning required.",
     "categories": "cs.CL"},
    {"title": "Bidirectional Attention Flow for Machine Comprehension",
     "abstract": "We introduce a multi-stage hierarchical process that represents the context at different levels of granularity and uses a bi-directional attention flow mechanism to obtain a query-aware context representation without early summarization.",
     "categories": "cs.CL"},
    {"title": "Adam: A Method for Stochastic Optimization",
     "abstract": "We introduce an algorithm for first-order gradient-based optimization of stochastic objective functions, based on adaptive estimates of lower-order moments. The method is computationally efficient, has little memory requirements and is well suited for large problems.",
     "categories": "cs.LG"},
    {"title": "Dropout: A Simple Way to Prevent Neural Networks from Overfitting",
     "abstract": "We present a technique for addressing overfitting in neural networks by randomly dropping units along with their connections during training. This prevents units from co-adapting too much and significantly improves generalization.",
     "categories": "cs.LG"},
    {"title": "Deep Residual Learning for Image Recognition (ResNet)",
     "abstract": "We present a residual learning framework to ease the training of networks that are substantially deeper than those used previously. We explicitly reformulate the layers as learning residual functions, enabling very deep networks to be optimized.",
     "categories": "cs.CV cs.LG"},
    {"title": "Generative Adversarial Networks",
     "abstract": "We propose a new framework for estimating generative models via an adversarial process, in which we simultaneously train two models: a generative model that captures the data distribution and a discriminative model that estimates the probability that a sample came from the data.",
     "categories": "cs.LG stat.ML"},
    {"title": "Convolutional Neural Networks for Sentence Classification",
     "abstract": "We report on experiments with convolutional neural networks trained on top of pre-trained word vectors for sentence-level classification tasks. A simple CNN with little hyperparameter tuning achieves excellent results on multiple benchmarks.",
     "categories": "cs.CL"},
    {"title": "Universal Language Model Fine-tuning for Text Classification (ULMFiT)",
     "abstract": "We propose an effective transfer learning method that can be applied to any task in NLP, and introduce techniques that are key for fine-tuning a language model. The approach significantly outperforms the state of the art on text classification.",
     "categories": "cs.CL"},
    {"title": "Scaling Laws for Neural Language Models",
     "abstract": "We study empirical scaling laws for language model performance on the cross-entropy loss. The loss scales as a power-law with model size, dataset size, and the amount of compute used for training, with trends spanning many orders of magnitude.",
     "categories": "cs.CL cs.LG"},
    {"title": "Chain-of-Thought Prompting Elicits Reasoning in Large Language Models",
     "abstract": "We explore how generating a chain of thought, a series of intermediate reasoning steps, significantly improves the ability of large language models to perform complex reasoning. Such reasoning abilities emerge naturally with sufficiently large models.",
     "categories": "cs.CL"},
    {"title": "LoRA: Low-Rank Adaptation of Large Language Models",
     "abstract": "We propose freezing the pretrained model weights and injecting trainable rank decomposition matrices into each layer of the Transformer, greatly reducing the number of trainable parameters for downstream tasks while maintaining quality.",
     "categories": "cs.CL cs.LG"},
    {"title": "Training language models to follow instructions with human feedback (InstructGPT)",
     "abstract": "We show an avenue for aligning language models with user intent on a wide range of tasks by fine-tuning with human feedback. We collect demonstrations and comparisons and use reinforcement learning from human feedback to fine-tune the model.",
     "categories": "cs.CL"},
    {"title": "Llama: Open and Efficient Foundation Language Models",
     "abstract": "We introduce a collection of foundation language models ranging from 7B to 65B parameters, trained on trillions of tokens using publicly available datasets exclusively. We show it is possible to train state-of-the-art models without proprietary data.",
     "categories": "cs.CL"},
    {"title": "FAISS: Billion-scale similarity search with GPUs",
     "abstract": "We propose a design for an approximate nearest-neighbor search library that takes advantage of GPUs to perform similarity search on billions of high-dimensional vectors, with applications to large-scale retrieval and clustering.",
     "categories": "cs.IR cs.LG"},
    {"title": "Reciprocal Rank Fusion outperforms Condorcet and individual Rank Learning Methods",
     "abstract": "We present a simple method for combining the document rankings from multiple information retrieval systems. Reciprocal rank fusion consistently yields better results than any individual system and several standard rank-fusion methods.",
     "categories": "cs.IR"},
    {"title": "Okapi BM25: A Probabilistic Relevance Framework for Information Retrieval",
     "abstract": "We review the probabilistic relevance framework and the BM25 ranking function, a bag-of-words retrieval function that ranks documents based on the query terms appearing in each document, regardless of their proximity.",
     "categories": "cs.IR"},
    {"title": "Latent Dirichlet Allocation",
     "abstract": "We describe a generative probabilistic model for collections of discrete data such as text corpora. LDA is a three-level hierarchical Bayesian model in which each item of a collection is modeled as a finite mixture over an underlying set of topics.",
     "categories": "cs.CL stat.ML"},
]


def papers() -> List[Dict]:
    return [dict(p) for p in PAPERS]


__all__ = ["PAPERS", "papers"]
